+/**
+ * Get budget alerts.
+ */
+export async function getBudgetAlerts(filter?: {
+  budgetId?: string;
+  acknowledged?: boolean;
+  since?: Date;
+  limit?: number;
+}): Promise<
+  Array<{
+    id: string;
+    budgetId: string;
+    threshold: number;
+    usedPercent: number;
+    usedUnits: number;
+    budgetUnits: number;
+    periodStart: Date;
+    periodEnd: Date;
+    acknowledged: boolean;
+    acknowledgedBy?: string;
+    acknowledgedAt?: Date;
+    createdAt: Date;
+  }>
+> {
+  const conditions = [];
+
+  if (filter?.budgetId) {
+    conditions.push(eq(budgetAlerts.budgetId, filter.budgetId));
+  }
+  if (filter?.acknowledged !== undefined) {
+    conditions.push(eq(budgetAlerts.acknowledged, filter.acknowledged));
+  }
+  if (filter?.since) {
+    conditions.push(gte(budgetAlerts.createdAt, filter.since));
+  }
+
+  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
+  const limit = filter?.limit ?? 50;
+
+  const rows = await db
+    .select()
+    .from(budgetAlerts)
+    .where(whereClause)
+    .orderBy(desc(budgetAlerts.createdAt))
+    .limit(limit);
+
+  return rows.map((row) => ({
+    id: row.id,
+    budgetId: row.budgetId,
+    threshold: row.threshold,
+    usedPercent: row.usedPercent,
+    usedUnits: row.usedUnits,
+    budgetUnits: row.budgetUnits,
+    periodStart: row.periodStart,
+    periodEnd: row.periodEnd,
+    acknowledged: row.acknowledged,
+    acknowledgedBy: row.acknowledgedBy ?? undefined,
+    acknowledgedAt: row.acknowledgedAt ?? undefined,
+    createdAt: row.createdAt,
+  }));
+}
+
+/**
+ * Acknowledge a budget alert.
+ */
+export async function acknowledgeBudgetAlert(
+  alertId: string,
+  acknowledgedBy?: string,
+): Promise<boolean> {
+  // Check if alert exists first
+  const existing = await db
+    .select()
+    .from(budgetAlerts)
+    .where(eq(budgetAlerts.id, alertId))
+    .limit(1);
+
+  if (existing.length === 0) {
+    return false;
+  }
+
+  const now = new Date();
+  await db
+    .update(budgetAlerts)
+    .set({
+      acknowledged: true,
+      acknowledgedBy: acknowledgedBy ?? null,
+      acknowledgedAt: now,
+    })
+    .where(eq(budgetAlerts.id, alertId));
+
+  return true;
+}
