+      predictedCostUnits: Math.round(f.predictedCostUnits * 1.3),
+      lowerBoundUnits: Math.round(f.lowerBoundUnits * 1.1),
+      upperBoundUnits: Math.round(f.upperBoundUnits * 1.5),
+    })),
+  });
+
+  return scenarios;
+}
