+/**
+ * Calculate forecast accuracy for a completed period.
+ */
+export async function calculateForecastAccuracy(forecastId: string): Promise<
+  | {
+      forecastId: string;
+      validatedDays: number;
+      mape: number;
+      rmse: number;
+      accuracy: number;
+    }
+  | undefined
