+      sumSquaredError += (actualUnits - df.predictedCostUnits) ** 2;
+    }
+  }
+
+  if (validatedDays === 0) {
+    return undefined;
+  }
+
+  const mape = (sumAbsPercent / validatedDays) * 100;
+  const rmse = Math.sqrt(sumSquaredError / validatedDays);
+  const accuracy = Math.max(0, 100 - mape);
+
+  return {
+    forecastId,
+    validatedDays,
+    mape,
+    rmse,
+    accuracy,
+  };
+}
