+/* BudgetGauge Styles */
+
+.budget-gauge {
+  background: var(--surface);
+  border-radius: var(--radius-lg);
+  padding: 1.25rem;
+  box-shadow: var(--shadow-sm);
+  display: flex;
+  flex-direction: column;
+  gap: 1rem;
+}
+
+.budget-gauge__header {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+}
+
+.budget-gauge__name {
+  margin: 0;
+  font-size: 1rem;
+  font-weight: 600;
+  color: var(--ink);
+}
+
+.budget-gauge__period {
+  font-size: 0.75rem;
+  color: var(--ink-muted);
+  background: var(--surface-muted);
+  padding: 0.25rem 0.5rem;
+  border-radius: var(--radius-sm);
+}
+
+.budget-gauge__visual {
+  position: relative;
+  width: 120px;
+  height: 120px;
+  margin: 0 auto;
+}
+
+.budget-gauge__svg {
+  width: 100%;
+  height: 100%;
+}
+
+.budget-gauge__progress {
+  transition: stroke-dashoffset var(--duration-slow) var(--ease-out);
+}
+
+/* Status colors for progress circle */
+.budget-gauge--healthy .budget-gauge__progress {
+  stroke: var(--positive);
+}
+
+.budget-gauge--caution .budget-gauge__progress {
+  stroke: var(--warning);
+}
+
+.budget-gauge--warning .budget-gauge__progress {
+  stroke: #e67e22;
+}
+
+.budget-gauge--critical .budget-gauge__progress {
+  stroke: var(--danger);
+}
+
+.budget-gauge__center {
+  position: absolute;
+  top: 50%;
+  left: 50%;
+  transform: translate(-50%, -50%);
+  text-align: center;
+}
+
+.budget-gauge__percent {
+  display: block;
+  font-size: 1.5rem;
+  font-weight: 700;
+  font-family: var(--font-display);
+  color: var(--ink);
+}
+
+.budget-gauge__label {
+  font-size: 0.75rem;
+  color: var(--ink-muted);
+}
+
+.budget-gauge__details {
+  display: flex;
+  flex-direction: column;
+  gap: 0.5rem;
+}
+
+.budget-gauge__row {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+}
+
+.budget-gauge__key {
+  font-size: 0.875rem;
+  color: var(--ink-muted);
+}
+
+.budget-gauge__value {
+  font-size: 0.875rem;
+  font-weight: 500;
+  color: var(--ink);
+}
+
+.budget-gauge__value--used {
+  color: var(--ink);
+}
+
+.budget-gauge__value--remaining {
+  color: var(--positive);
+}
+
+.budget-gauge--critical .budget-gauge__value--remaining {
+  color: var(--danger);
+}
+
+.budget-gauge__alert {
+  margin-top: 0.5rem;
+  padding: 0.5rem;
+  font-size: 0.75rem;
+  font-weight: 500;
+  text-align: center;
+  border-radius: var(--radius-sm);
+  background: rgba(196, 77, 65, 0.1);
+  color: var(--danger);
+}

