+/* CostBreakdownChart Styles */
+
+.cost-breakdown {
+  background: var(--surface);
+  border-radius: var(--radius-lg);
+  padding: 1.25rem;
+  box-shadow: var(--shadow-sm);
+}
+
+.cost-breakdown__header {
+  display: flex;
+  justify-content: space-between;
