+  flex-wrap: wrap;
+}
+
+.cost-breakdown__header h3 {
+  margin: 0;
+  font-size: 1rem;
+  font-weight: 600;
+  color: var(--ink);
+}
+
+.cost-breakdown__total {
+  display: block;
+  font-size: 0.75rem;
+  color: var(--ink-muted);
+  margin-top: 0.25rem;
+}
+
+.cost-breakdown__dimensions {
+  display: flex;
+  gap: 0.25rem;
+  background: var(--surface-muted);
+  padding: 0.25rem;
+  border-radius: var(--radius-sm);
